import React from 'react';
import { Card, Stack, Row, Text, Divider, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function WeatherCard({
  city = 'Unknown City',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = '°C',
  forecast = [],
}: Props) {
  const { motionEnabled } = useMotion();

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        border={true}
        style={{
          backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
          borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
          borderWidth: '1px',
          borderStyle: 'solid',
          animation: motionEnabled ? animation.slideInUp : 'none',
        }}
      >
        <Stack direction="vertical" gap={16}>
          {/* Header Section: City & Condition */}
          <Stack direction="vertical" gap={4} align="center">
            <Text
              variant="h3"
              color="var(--ggui-color-onSurface, #18181b)"
              align="center"
              weight="semibold"
            >
              {city}
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              align="center"
            >
              {condition}
            </Text>
          </Stack>

          {/* Current Weather Section */}
          <Stack direction="vertical" gap={12} align="center">
            <Text
              variant="h1"
              color="var(--ggui-color-primary-600, #0284c7)"
              weight="bold"
              align="center"
            >
              {temperature}
              <span style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)' }}>{unit}</span>
            </Text>

            {/* Humidity & Wind Speed Row */}
            <Row gap={16} justify="center" align="center">
              {/* Humidity Detail */}
              <Stack direction="vertical" gap={4} align="center">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                >
                  Humidity
                </Text>
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurface, #18181b)"
                  weight="semibold"
                >
                  {humidity}%
                </Text>
              </Stack>

              {/* Wind Speed Detail */}
              <Stack direction="vertical" gap={4} align="center">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                >
                  Wind
                </Text>
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurface, #18181b)"
                  weight="semibold"
                >
                  {windSpeed} km/h
                </Text>
              </Stack>
            </Row>
          </Stack>

          {/* Divider */}
          {forecast.length > 0 && (
            <Divider
              orientation="horizontal"
              margin={8}
              style={{
                borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
              }}
            />
          )}

          {/* 5-Day Forecast Strip */}
          {forecast.length > 0 && (
            <Stack direction="vertical" gap={8}>
              <Text
                variant="label"
                color="var(--ggui-color-onSurface, #18181b)"
                weight="semibold"
              >
                5-Day Forecast
              </Text>
              <Row
                direction="horizontal"
                gap={8}
                wrap={true}
                align="start"
                justify="start"
              >
                {forecast.map((item, index) => (
                  <Stack
                    key={`forecast-${index}`}
                    direction="vertical"
                    gap={4}
                    align="center"
                    style={{
                      padding: 'var(--ggui-spacing-2, 8px)',
                      backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      minWidth: '70px',
                      animation: motionEnabled
                        ? `${animation.slideInUp}`
                        : 'none',
                      animationDelay: motionEnabled ? `${index * 50}ms` : '0ms',
                    }}
                  >
                    {/* Day Name */}
                    {item.day && (
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurface, #18181b)"
                        weight="semibold"
                        align="center"
                      >
                        {item.day}
                      </Text>
                    )}

                    {/* Weather Icon/Emoji */}
                    {item.icon && (
                      <div
                        style={{
                          fontSize: 'var(--ggui-font-size-2xl, 24px)',
                          lineHeight: '1',
                        }}
                        role="img"
                        aria-label={`Weather icon for ${item.day || 'forecast'}`}
                      >
                        {item.icon}
                      </div>
                    )}

                    {/* High Temperature */}
                    {item.high !== undefined && (
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurface, #18181b)"
                        weight="semibold"
                        align="center"
                      >
                        {item.high}
                        {unit}
                      </Text>
                    )}

                    {/* Low Temperature */}
                    {item.low !== undefined && (
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        align="center"
                      >
                        {item.low}
                        {unit}
                      </Text>
                    )}
                  </Stack>
                ))}
              </Row>
            </Stack>
          )}
        </Stack>
      </Card>
    </>
  );
}

