import React from 'react';
import { Card, Stack, Row, Text, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * Displays current weather details and a 5-day forecast strip.
 */
export default function WeatherCard({
  city = 'London',
  temperature = 18,
  condition = 'Cloudy',
  humidity = 72,
  windSpeed = 15,
  unit = 'C',
  forecast = []
}: Props) {

  // Logic to determine emoji based on condition text if icon isn't provided
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle') || c.includes('showers')) return '🌧️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('fog') || c.includes('mist')) return '🌫️';
    return '⛅';
  };

  return (
    <Card 
      shadow="md" 
      border 
      padding={0} 
      style={{ 
        overflow: 'hidden', 
        maxWidth: '450px',
        width: '100%',
        backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        margin: '0 auto'
      }}
    >
      {/* Main Stats Area */}
      <Box 
        padding="var(--ggui-spacing-6, 24px)" 
        style={{ 
          background: 'linear-gradient(180deg, var(--ggui-color-primary-50, #f0f9ff) 0%, var(--ggui-color-surface, #fafafa) 100%)' 
        }}
      >
        <Stack gap={24}>
          {/* Location and Main Icon */}
          <Row justify="between" align="start">
            <Stack gap={4}>
              <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                {city}
              </Text>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {condition}
              </Text>
            </Stack>
            <div style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)', lineHeight: 1 }} aria-hidden="true">
              {getConditionEmoji(condition)}
            </div>
          </Row>

          {/* Big Temperature Display */}
          <Row justify="center" align="center">
            <Text 
              variant="h1" 
              weight="bold" 
              style={{ 
                fontSize: '4rem', 
                lineHeight: 1,
                color: 'var(--ggui-color-onSurface, #18181b)',
                textAlign: 'center'
              }}
            >
              {temperature}°{unit}
            </Text>
          </Row>

          {/* Detail Pills (Humidity/Wind) */}
          <Row 
            gap={0} 
            justify="around" 
            align="center"
            style={{ 
              backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)', 
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
              padding: 'var(--ggui-spacing-3, 12px)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
            }}
          >
            <Stack align="center" gap={4}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
              <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{humidity}%</Text>
            </Stack>
            <Divider orientation="vertical" margin={8} />
            <Stack align="center" gap={4}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
              <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{windSpeed} mph</Text>
            </Stack>
          </Row>
        </Stack>
      </Box>

      <Divider margin={0} />

      {/* 5-Day Forecast strip */}
      <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-surface, #fafafa)">
        <Row gap={12} justify="between" align="center">
          {forecast.map((item, idx) => (
            <Stack 
              key={`${item.day || 'day'}-${idx}`} 
              align="center" 
              gap={8} 
              style={{ flex: '1 0 0', minWidth: '60px' }}
            >
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {item.day || '---'}
              </Text>
              <div style={{ fontSize: 'var(--ggui-font-size-xl, 20px)' }} aria-hidden="true">
                {item.icon || '☀️'}
              </div>
              <Stack gap={0} align="center">
                <Text variant="caption" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                  {item.high ?? '--'}°
                </Text>
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                  {item.low ?? '--'}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Row>
      </Box>
    </Card>
  );
}

