 */
export default function WeatherCard({
  city = "San Francisco",
  temperature = 72,
  condition = "Partly Cloudy",
  humidity = 45,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: "Mon", icon: "☀️", high: 75, low: 58 },
    { day: "Tue", icon: "☁️", high: 70, low: 55 },
    { day: "Wed", icon: "🌦️", high: 68, low: 54 },
    { day: "Thu", icon: "☀️", high: 74, low: 57 },
    { day: "Fri", icon: "☀️", high: 78, low: 60 },
  ],
}: Props) {
  // Simple mapping for common weather conditions to emojis if needed
  // (though the design spec suggests condition might already come with context)
  const getWeatherEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    if (c.includes('fog') || c.includes('mist')) return '🌫️';
    return '⛅';
  };

  return (
    <Container maxWidth="sm" padding={16}>
      <Card
        padding={24}
        shadow="md"
        style={{
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
        }}
      >
        <Stack gap={24}>
          {/* Header Section */}
          <Row justify="between" align="start">
            <Stack gap={4}>
              <Text variant="h2" weight="bold">
                {city}
              </Text>
              <Text
                variant="body"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {condition}
              </Text>
            </Stack>
            <span
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                lineHeight: 1,
              }}
              role="img"
              aria-label={condition}
            >
              {getWeatherEmoji(condition)}
            </span>
          </Row>

          {/* Main Temp Section */}
          <Box paddingY={8}>
            <Row align="end" gap={4}>
              <Text
                style={{
                  fontSize: '64px',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  lineHeight: '1',
                  color: 'var(--ggui-color-onSurface, #18181b)',
                }}
              >
                {Math.round(temperature)}
              </Text>
              <Text
                variant="h2"
                weight="medium"
                color="var(--ggui-color-primary-600, #0284c7)"
                style={{ paddingBottom: '8px' }}
              >
                °{unit}
              </Text>
            </Row>
          </Box>

          {/* Stats Section */}
          <Row justify="between" style={{ width: '100%' }}>
            <Stack align="center" gap={4} style={{ flex: 1 }}>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                weight="bold"
                style={{ letterSpacing: '0.05em' }}
              >
                HUMIDITY
              </Text>
              <Text variant="body" weight="semibold">
                {humidity}%
              </Text>
            </Stack>
            <div style={{ width: '1px', alignSelf: 'stretch', background: 'var(--ggui-color-outline, #d4d4d8)' }} />
            <Stack align="center" gap={4} style={{ flex: 1 }}>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                weight="bold"
                style={{ letterSpacing: '0.05em' }}
              >
                WIND
              </Text>
              <Text variant="body" weight="semibold">
                {windSpeed} <span style={{ fontSize: 'var(--ggui-font-size-xs, 12px)', fontWeight: 'normal' }}>km/h</span>
              </Text>
            </Stack>
          </Row>

          <Divider margin={8} />

          {/* Forecast Section */}
          <Stack gap={16}>
            <Text
              variant="label"
              weight="bold"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              style={{ fontSize: '11px', letterSpacing: '0.1em' }}
            >
              5-DAY FORECAST
            </Text>
            <Row gap={8} justify="between" style={{ overflowX: 'auto', paddingBottom: '4px' }}>
              {forecast.map((item, index) => (
                <Stack
                  key={item.day || `day-${index}`}
                  align="center"
                  gap={8}
                  style={{
                    flex: '1 0 0',
                    minWidth: '60px',
                    padding: 'var(--ggui-spacing-3, 12px) var(--ggui-spacing-2, 8px)',
                    borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                    background: 'var(--ggui-color-surface, #fafafa)',
                    border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    transition: 'transform 200ms ease',
                  }}
                >
                  <Text variant="caption" weight="bold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {item.day}
                  </Text>
                  <span style={{ fontSize: 'var(--ggui-font-size-xl, 20px)' }} role="img" aria-label="weather">
                    {item.icon || '☀️'}
                  </span>
                  <Stack gap={0} align="center">
                    <Text variant="bodySmall" weight="bold">
                      {item.high}°
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {item.low}°
                    </Text>
                  </Stack>
                </Stack>
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
